import streamlit as st
import pandas as pd
import plotly.express as px
import plotly.graph_objects as go
import os

# Page configuration
st.set_page_config(page_title="Dashboard2Code Evaluation Board", layout="wide")

st.title("📊 Dashboard2Code Experiment Evaluation Dashboard")
st.markdown(
    "This dashboard is based on report data generated by `generate_experiment_report.py`. "
    "It displays model performance across static metrics, dynamic execution, and figure restoration accuracy."
)

# ================= Data Loading =================

REPORT_DIR = "reports"
OVERALL_PATH = os.path.join(REPORT_DIR, "report_overall.csv")
RAW_PATH = os.path.join(REPORT_DIR, "full_analysis_raw.csv")


@st.cache_data
def load_data():
    if not os.path.exists(OVERALL_PATH) or not os.path.exists(RAW_PATH):
        return None, None
    df_overall = pd.read_csv(OVERALL_PATH)
    df_raw = pd.read_csv(RAW_PATH)
    return df_overall, df_raw


df_overall, df_raw = load_data()

if df_overall is None:
    st.error(f"❌ Report files not found. Please run `python generate_experiment_report.py` to generate data first.")
    st.stop()

# ================= Sidebar Configuration =================

st.sidebar.header("Filters & Configuration")
selected_models = st.sidebar.multiselect(
    "Select Models to Compare",
    options=df_overall["Model"].unique(),
    default=df_overall["Model"].unique()
)

# Metric group definitions
static_metrics = ["Component coverage", "TED", "Semantic"]
dynamic_metrics = ["Code execution rate", "Task execution rate"]
figure_detail_metrics = ["Fig-Style", "Fig-Text", "Fig-Data", "Fig-Type"]
llm_metrics = ["LLM-Visual", "LLM-Behavior"]

# ================= Overall Metrics Comparison =================

st.header("1. Overall Metrics Comparison")
filtered_overall = df_overall[df_overall["Model"].isin(selected_models)]

# Display Table
st.dataframe(filtered_overall.style.highlight_max(axis=0, color='lightgreen'))

# Radar Chart Comparison
st.subheader("Model Capability Distribution (Radar Chart)")
target_model = st.selectbox("Select Target Model for Analysis", options=selected_models)


def create_radar_chart(model_name, df):
    categories = ["Code execution rate", "Task execution rate", "Figure", "Component coverage", "Semantic"]

    fig = go.Figure()
    # Add selected model
    model_vals = df[df["Model"] == model_name][categories].values.flatten()
    fig.add_trace(go.Scatterpolar(r=model_vals, theta=categories, fill='toself', name=model_name))

    # Add average as baseline
    avg_vals = df[categories].mean().values
    fig.add_trace(go.Scatterpolar(r=avg_vals, theta=categories, fill='toself', name='Average', line_color='gray'))

    fig.update_layout(polar=dict(radialaxis=dict(visible=True, range=[0, 100])), showlegend=True)
    return fig


st.plotly_chart(create_radar_chart(target_model, filtered_overall))

# ================= Figure Detail Analysis =================

st.divider()
st.header("2. Figure Restoration Depth Analysis")
st.info("Displays matching scores across four dimensions: Style, Text, Data, and Type.")

fig_melted = filtered_overall.melt(id_vars="Model", value_vars=figure_detail_metrics, var_name="Dimension",
                                   value_name="Score")
fig_bar = px.bar(fig_melted, x="Dimension", y="Score", color="Model", barmode="group", text_auto='.2f',
                 title="Figure Dimensional Matching Comparison")
st.plotly_chart(fig_bar, use_container_width=True)

# ================= Difficulty Distribution Analysis =================

st.divider()
st.header("3. Performance by Difficulty")

df_diff = df_raw[df_raw["Model"].isin(selected_models)]
diff_summary = df_diff.groupby(["Model", "Difficulty"])["Figure"].mean().reset_index()

fig_diff = px.line(diff_summary, x="Difficulty", y="Figure", color="Model", markers=True,
                   title="Figure Score Trend by Difficulty Level",
                   labels={"Difficulty": "Difficulty Level (1-3)", "Figure": "Average Figure Score"})
st.plotly_chart(fig_diff, use_container_width=True)

# ================= Raw Data Explorer =================

st.divider()
st.header("4. Raw Data Explorer")
with st.expander("View Details"):
    search_id = st.text_input("Search specific AppID (e.g., 1001)")
    if search_id:
        st.write(df_raw[df_raw["AppID"].astype(str).str.contains(search_id)])
    else:
        st.write(df_raw[df_raw["Model"].isin(selected_models)])